import React, { useState } from "react";
import "../../styles/auth.css";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

function Register() {
  const navigate = useNavigate();
  const { register } = useAuth();
  const [form, setForm] = useState({
    firstName: "", lastName: "", email: "",
    password: "", confirmPassword: "",
    phone: "", gender: "", dob: "", role: "freelancer",
  });
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleRegister = async (e) => {
    e.preventDefault();
    setMessage("");
    if (form.password !== form.confirmPassword) { setMessage("❌ Passwords do not match!"); return; }
    if (form.phone.length !== 10) { setMessage("❌ Enter valid 10-digit phone!"); return; }
    setLoading(true);
    const result = await register({
      name: `${form.firstName} ${form.lastName}`.trim(),
      email: form.email, password: form.password,
      phone: form.phone, gender: form.gender, dob: form.dob, role: form.role,
    });
    setLoading(false);
    if (result.success) {
      setMessage("✅ Registered! Redirecting...");
      setTimeout(() => navigate("/login"), 1500);
    } else { setMessage(result.message); }
  };

  const inputStyle = {
    width: "100%", padding: "8px 12px", fontSize: "13px",
    borderRadius: "8px", border: "1.5px solid #e5e7eb",
    outline: "none", background: "#f9fafb", boxSizing: "border-box"
  };
  const labelStyle = {
    fontSize: "12px", fontWeight: "600", color: "#374151",
    display: "block", marginBottom: "4px"
  };

  return (
    <div style={{ minHeight: "100vh", display: "grid", gridTemplateColumns: "1fr 1fr" }}>

      {/* ===== LEFT PANEL ===== */}
      <div style={{
        background: "linear-gradient(135deg, #0f766e 0%, #134e4a 60%, #0c3b36 100%)",
        display: "flex", flexDirection: "column", justifyContent: "center",
        padding: "60px 50px", position: "relative", overflow: "hidden",
      }}>
        {/* Decorative circles */}
        <div style={{ position: "absolute", width: "320px", height: "320px", borderRadius: "50%", background: "rgba(255,255,255,0.05)", top: "-80px", right: "-80px" }} />
        <div style={{ position: "absolute", width: "220px", height: "220px", borderRadius: "50%", background: "rgba(255,255,255,0.05)", bottom: "-50px", left: "-50px" }} />

        {/* ✅ BIGGER heading */}
        <h1 style={{ fontSize: "42px", fontWeight: "800", color: "white", lineHeight: 1.15, marginBottom: "16px", zIndex: 1 }}>
          Join<br /><span style={{ color: "#5eead4" }}>FreelanceHub</span>
        </h1>

        {/* ✅ BIGGER description */}
        <p style={{ fontSize: "16px", color: "rgba(255,255,255,0.8)", lineHeight: 1.6, marginBottom: "36px", zIndex: 1, maxWidth: "340px" }}>
          Connect with top talent or find exciting projects today.
        </p>

        {/* ✅ BIGGER feature items */}
        <div style={{ display: "flex", flexDirection: "column", gap: "20px", zIndex: 1 }}>
          {[
            ["💻", "Freelancers — showcase skills & get hired"],
            ["🏢", "Clients — post projects & find experts"],
            ["💬", "Chat directly with your team"],
            ["📊", "Track earnings and project progress"],
          ].map(([icon, text], i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", gap: "14px" }}>
              <div style={{
                width: "44px", height: "44px",
                background: "rgba(255,255,255,0.12)",
                borderRadius: "10px",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: "20px", flexShrink: 0,
              }}>{icon}</div>
              <span style={{ fontSize: "15px", color: "rgba(255,255,255,0.88)", lineHeight: 1.4 }}>{text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ===== RIGHT PANEL ===== */}
      <div style={{ display: "flex", justifyContent: "center", alignItems: "center", background: "#f8fafc", padding: "30px", overflowY: "auto" }}>
        <div style={{
          width: "100%", maxWidth: "480px",
          background: "white", padding: "28px 32px",
          borderRadius: "16px",
          boxShadow: "0 4px 24px rgba(0,0,0,0.08)",
          border: "1px solid #e5e7eb",
        }}>

          {/* HEADER */}
          <div style={{ textAlign: "center", marginBottom: "18px" }}>
            <div style={{ fontSize: "24px", marginBottom: "6px" }}>🧳</div>
            <h2 style={{ fontSize: "20px", fontWeight: "700", margin: "0 0 4px", color: "#111827" }}>Create Account</h2>
            <p style={{ fontSize: "12px", color: "#6b7280", margin: 0 }}>Join FreelanceHub today</p>
          </div>

          {/* TOGGLE */}
          <div style={{ display: "flex", background: "#f3f4f6", borderRadius: "9px", padding: "4px", marginBottom: "16px" }}>
            {[["Login", false], ["Register", true]].map(([label, active]) => (
              <button key={label} onClick={() => !active && navigate("/login")} style={{
                flex: 1, padding: "8px", fontSize: "13px", fontWeight: "600",
                borderRadius: "6px", border: "none", cursor: "pointer",
                background: active ? "#0f766e" : "transparent",
                color: active ? "white" : "#6b7280",
                boxShadow: active ? "0 1px 4px rgba(15,118,110,0.3)" : "none",
              }}>{label}</button>
            ))}
          </div>

          {message && (
            <p style={{
              textAlign: "center", fontSize: "12px", marginBottom: "10px",
              color: message.startsWith("✅") ? "#059669" : "#ef4444",
              background: message.startsWith("✅") ? "#f0fdf4" : "#fef2f2",
              border: `1px solid ${message.startsWith("✅") ? "#bbf7d0" : "#fecaca"}`,
              padding: "6px 10px", borderRadius: "7px",
            }}>{message}</p>
          )}

          <form onSubmit={handleRegister} style={{ display: "flex", flexDirection: "column", gap: "12px" }}>

            <div style={{ display: "flex", gap: "10px" }}>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>First Name</label>
                <input type="text" name="firstName" placeholder="John" value={form.firstName} onChange={handleChange} required style={inputStyle} />
              </div>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>Last Name</label>
                <input type="text" name="lastName" placeholder="Doe" value={form.lastName} onChange={handleChange} required style={inputStyle} />
              </div>
            </div>

            <div>
              <label style={labelStyle}>Email</label>
              <input type="email" name="email" placeholder="john@example.com" value={form.email} onChange={handleChange} required style={inputStyle} />
            </div>

            <div style={{ display: "flex", gap: "10px" }}>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>Password</label>
                <input type="password" name="password" placeholder="••••••••" value={form.password} onChange={handleChange} required style={inputStyle} />
              </div>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>Confirm Password</label>
                <input type="password" name="confirmPassword" placeholder="••••••••" value={form.confirmPassword} onChange={handleChange} required style={inputStyle} />
              </div>
            </div>

            <div>
              <label style={labelStyle}>Phone Number</label>
              <input type="tel" name="phone" placeholder="9876543210" maxLength="10" value={form.phone} onChange={handleChange} required style={inputStyle} />
            </div>

            <div style={{ display: "flex", gap: "10px" }}>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>Gender</label>
                <select name="gender" value={form.gender} onChange={handleChange} required style={inputStyle}>
                  <option value="">Select</option>
                  <option value="male">Male</option>
                  <option value="female">Female</option>
                  <option value="other">Other</option>
                </select>
              </div>
              <div style={{ flex: 1 }}>
                <label style={labelStyle}>Date of Birth</label>
                <input type="date" name="dob" value={form.dob} onChange={handleChange} required style={inputStyle} />
              </div>
            </div>

            <div>
              <label style={labelStyle}>Register As</label>
              <div style={{ display: "flex", gap: "10px" }}>
                {[["freelancer","👤","Freelancer"],["client","👥","Client"]].map(([val, icon, label]) => (
                  <div key={val} onClick={() => setForm({ ...form, role: val })} style={{
                    flex: 1, textAlign: "center", padding: "10px 8px",
                    borderRadius: "9px", cursor: "pointer",
                    border: form.role === val ? "2px solid #0f766e" : "1.5px solid #e5e7eb",
                    background: form.role === val ? "#f0fdf9" : "#f9fafb",
                  }}>
                    <span style={{ fontSize: "18px" }}>{icon}</span>
                    <p style={{ fontSize: "12px", fontWeight: "600", margin: "3px 0 0", color: form.role === val ? "#0f766e" : "#6b7280" }}>{label}</p>
                  </div>
                ))}
              </div>
            </div>

            <button type="submit" disabled={loading} style={{
              width: "100%", padding: "11px", fontSize: "14px", fontWeight: "600",
              borderRadius: "9px", border: "none",
              background: "linear-gradient(135deg, #0f766e, #134e4a)",
              color: "white", cursor: loading ? "not-allowed" : "pointer",
              opacity: loading ? 0.7 : 1,
            }}>
              {loading ? "Creating..." : "Create Account"}
            </button>

          </form>
        </div>
      </div>
    </div>
  );
}

export default Register;
